export interface Chapter {
  title: string;
  content: string; // HTML or Markdown content
}

export interface Book {
  id: string;
  title: string;
  author: string;
  coverImage?: string; // Base64 or URL
  chapters: Chapter[];
  createdAt: number;
  progress: {
    chapterIndex: number;
    scrollPosition: number;
  };
}

export interface ConversionStatus {
  state: 'idle' | 'uploading' | 'processing' | 'success' | 'error';
  message?: string;
}

export enum ViewMode {
  LIBRARY = 'LIBRARY',
  READER = 'READER',
  IMPORTER = 'IMPORTER',
}

import { Book } from '../types';

const STORAGE_KEY = 'lumina_library_v1';

// Simulating a Redis-like key-value store interface
export const storageService = {
  getLibrary: (): Book[] => {
    try {
      const data = localStorage.getItem(STORAGE_KEY);
      return data ? JSON.parse(data) : [];
    } catch (e) {
      console.error("Failed to load library", e);
      return [];
    }
  },

  saveBook: (book: Book): void => {
    const library = storageService.getLibrary();
    // Check if book exists, update if so
    const existingIndex = library.findIndex(b => b.id === book.id);
    if (existingIndex >= 0) {
      library[existingIndex] = book;
    } else {
      library.unshift(book);
    }
    localStorage.setItem(STORAGE_KEY, JSON.stringify(library));
  },

  deleteBook: (bookId: string): void => {
    const library = storageService.getLibrary();
    const newLibrary = library.filter(b => b.id !== bookId);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(newLibrary));
  },

  getBook: (bookId: string): Book | undefined => {
    const library = storageService.getLibrary();
    return library.find(b => b.id === bookId);
  },

  updateProgress: (bookId: string, chapterIndex: number, scrollPosition: number) => {
    const library = storageService.getLibrary();
    const bookIndex = library.findIndex(b => b.id === bookId);
    if (bookIndex >= 0) {
      library[bookIndex].progress = { chapterIndex, scrollPosition };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(library));
    }
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { Book, Chapter } from '../types';

// Helper to encode file to base64
export const fileToGenerativePart = async (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      // Remove data url prefix (e.g. "data:application/pdf;base64,")
      const base64Data = base64String.split(',')[1];
      resolve(base64Data);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const convertPdfToBook = async (file: File, apiKey: string): Promise<Partial<Book>> => {
  if (!apiKey) {
    throw new Error("API Key is missing");
  }

  const ai = new GoogleGenAI({ apiKey });
  const base64Data = await fileToGenerativePart(file);

  const model = "gemini-2.5-flash";

  const prompt = `
    You are an expert ebook converter. 
    Analyze the attached PDF document. 
    Extract the Title, Author, and the full content of the book.
    Organize the content into logical chapters. 

    If the text is messy (due to OCR), clean it up and format it nicely as HTML paragraphs (<p>).
    Do NOT summarize. Extract as much of the original content as possible while maintaining structure.

    Return a JSON object matching the schema.
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: file.type,
              data: base64Data
            }
          },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            author: { type: Type.STRING },
            chapters: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  content: { type: Type.STRING, description: "The chapter content in HTML format (e.g. <p>...)" }
                }
              }
            }
          }
        }
      }
    });

    if (!response.text) {
      throw new Error("No response from Gemini");
    }

    const data = JSON.parse(response.text);

    return {
      title: data.title || "Untitled Book",
      author: data.author || "Unknown Author",
      chapters: data.chapters || []
    };

  } catch (error) {
    console.error("Gemini Conversion Error:", error);
    throw error;
  }
};

