import React, { useState, useEffect, useRef } from 'react';
import { Book } from '../types';
import { ArrowLeft, Settings, ChevronLeft, ChevronRight, Menu, CheckCircle, Circle } from 'lucide-react';

interface ReaderProps {
  book: Book;
  onBack: () => void;
  onUpdateProgress: (progress: Book['progress']) => void;
}

export const Reader: React.FC<ReaderProps> = ({ book, onBack, onUpdateProgress }) => {
  const [currentChapterIndex, setCurrentChapterIndex] = useState(book.progress.chapterIndex);
  const [completedChapters, setCompletedChapters] = useState<number[]>(book.progress.completedChapters || []);
  const [fontSize, setFontSize] = useState(18);
  const [theme, setTheme] = useState<'light' | 'sepia' | 'dark'>('sepia');
  const [showControls, setShowControls] = useState(true);
  const [showToc, setShowToc] = useState(false);

  const contentRef = useRef<HTMLDivElement>(null);

  const currentChapter = book.chapters[currentChapterIndex];
  const isCurrentChapterRead = completedChapters.includes(currentChapterIndex);

  // Load progress on mount or chapter change to restore scroll
  useEffect(() => {
     if (currentChapterIndex === book.progress.chapterIndex) {
         setTimeout(() => {
             window.scrollTo(0, book.progress.scrollPosition);
         }, 100);
     } else {
         window.scrollTo(0, 0);
     }
  }, [currentChapterIndex]);

  // Sync scroll position to parent
  useEffect(() => {
      const handleScroll = () => {
          onUpdateProgress({
            chapterIndex: currentChapterIndex,
            scrollPosition: window.scrollY,
            completedChapters
          });
      };

      window.addEventListener('scroll', handleScroll);
      return () => window.removeEventListener('scroll', handleScroll);
  }, [currentChapterIndex, completedChapters, onUpdateProgress]);

  const markChapterAsRead = (index: number) => {
    if (!completedChapters.includes(index)) {
      const newCompleted = [...completedChapters, index];
      setCompletedChapters(newCompleted);
      onUpdateProgress({
        chapterIndex: currentChapterIndex,
        scrollPosition: window.scrollY,
        completedChapters: newCompleted
      });
    }
  };

  const handleNextChapter = () => {
    // Auto-mark as read when proceeding to next chapter
    markChapterAsRead(currentChapterIndex);

    if (currentChapterIndex < book.chapters.length - 1) {
      setCurrentChapterIndex(prev => prev + 1);
      window.scrollTo(0, 0);
    }
  };

  const handlePrevChapter = () => {
    if (currentChapterIndex > 0) {
      setCurrentChapterIndex(prev => prev - 1);
      window.scrollTo(0, 0);
    }
  };

  const toggleControls = () => {
    setShowControls(prev => !prev);
  };

  const getThemeColors = () => {
    switch(theme) {
      case 'dark': return 'bg-gray-900 text-gray-300';
      case 'sepia': return 'bg-paper-dark text-ink';
      default: return 'bg-white text-gray-900';
    }
  };

  // Calculate overall progress
  const progressPercent = Math.round((completedChapters.length / book.chapters.length) * 100);

  return (
    <div className={`min-h-screen transition-colors duration-500 ${getThemeColors()} font-serif`}>
      {/* Sticky Header */}
      <div 
        className={`fixed top-0 left-0 right-0 p-4 flex flex-col justify-center transition-transform duration-300 z-50 ${
          showControls ? 'translate-y-0' : '-translate-y-full'
        } ${theme === 'dark' ? 'bg-gray-900/95' : 'bg-white/95'} backdrop-blur-sm border-b ${theme === 'dark' ? 'border-gray-800' : 'border-gray-100'}`}
      >
        <div className="flex justify-between items-center w-full max-w-5xl mx-auto">
            <div className="flex items-center gap-4">
                <button onClick={onBack} className="p-2 rounded-full hover:bg-gray-100/10 transition-colors">
                <ArrowLeft size={20} className={theme === 'dark' ? 'text-gray-300' : 'text-gray-700'} />
                </button>
                <button onClick={() => setShowToc(!showToc)} className="p-2 rounded-full hover:bg-gray-100/10 transition-colors md:hidden">
                    <Menu size={20} className={theme === 'dark' ? 'text-gray-300' : 'text-gray-700'} />
                </button>
                <div className="hidden md:block">
                     <h2 className="font-sans font-medium text-sm truncate max-w-[200px]">{book.title}</h2>
                     <div className="w-32 h-1 bg-gray-200 rounded-full mt-1 overflow-hidden">
                        <div className="h-full bg-indigo-500 transition-all duration-300" style={{ width: `${progressPercent}%` }}></div>
                     </div>
                </div>
            </div>

            <div className="flex items-center gap-4">
                <div className="flex items-center gap-2 bg-gray-100/10 rounded-full p-1 border border-gray-200/20">
                    <button 
                        onClick={() => setFontSize(Math.max(14, fontSize - 2))}
                        className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-500/10 font-sans text-sm"
                    >
                        A-
                    </button>
                    <span className="text-xs font-sans w-4 text-center">{fontSize}</span>
                    <button 
                        onClick={() => setFontSize(Math.min(32, fontSize + 2))}
                        className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-500/10 font-sans text-lg"
                    >
                        A+
                    </button>
                </div>

                <div className="flex items-center gap-1">
                    <button onClick={() => setTheme('light')} className={`w-6 h-6 rounded-full border border-gray-300 bg-white ${theme === 'light' ? 'ring-2 ring-indigo-500' : ''}`} />
                    <button onClick={() => setTheme('sepia')} className={`w-6 h-6 rounded-full border border-orange-200 bg-[#eaddcf] ${theme === 'sepia' ? 'ring-2 ring-indigo-500' : ''}`} />
                    <button onClick={() => setTheme('dark')} className={`w-6 h-6 rounded-full border border-gray-700 bg-gray-900 ${theme === 'dark' ? 'ring-2 ring-indigo-500' : ''}`} />
                </div>
            </div>
        </div>
      </div>

      {/* TOC Sidebar */}
      {showToc && (
        <div className="fixed inset-0 z-40 bg-black/50" onClick={() => setShowToc(false)}>
            <div 
                className={`absolute left-0 top-0 bottom-0 w-80 max-w-[80%] ${theme === 'dark' ? 'bg-gray-900' : 'bg-white'} shadow-2xl overflow-y-auto p-6`}
                onClick={e => e.stopPropagation()}
            >
                <h3 className="font-sans font-bold text-lg mb-6">Table of Contents</h3>
                <ul className="space-y-4">
                    {book.chapters.map((chap, idx) => {
                        const isRead = completedChapters.includes(idx);
                        return (
                            <li key={idx} className="flex items-start gap-3">
                                <button
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        if (isRead) {
                                            const newCompleted = completedChapters.filter(c => c !== idx);
                                            setCompletedChapters(newCompleted);
                                            onUpdateProgress({ ...book.progress, completedChapters: newCompleted });
                                        } else {
                                            markChapterAsRead(idx);
                                        }
                                    }}
                                    className={`mt-1 flex-shrink-0 hover:opacity-80 transition-opacity ${isRead ? 'text-green-500' : 'text-gray-300'}`}
                                >
                                    {isRead ? <CheckCircle size={16} /> : <Circle size={16} />}
                                </button>
                                <button 
                                    onClick={() => {
                                        setCurrentChapterIndex(idx);
                                        setShowToc(false);
                                        window.scrollTo(0,0);
                                    }}
                                    className={`text-left w-full hover:text-indigo-500 transition-colors ${currentChapterIndex === idx ? 'text-indigo-500 font-bold' : ''}`}
                                >
                                    {chap.title}
                                </button>
                            </li>
                        );
                    })}
                </ul>
            </div>
        </div>
      )}

      {/* Main Content */}
      <div 
        className="max-w-2xl mx-auto px-6 py-24 md:px-12 min-h-screen cursor-text"
        onClick={toggleControls}
      >
        <div className="mb-12 text-center">
             <h3 className="font-sans text-xs uppercase tracking-widest opacity-50 mb-2">Chapter {currentChapterIndex + 1}</h3>
             <h1 className="text-3xl md:text-4xl font-bold">{currentChapter.title}</h1>
        </div>

        <div 
            ref={contentRef}
            style={{ fontSize: `${fontSize}px`, lineHeight: '1.8' }}
            className="prose prose-lg max-w-none prose-p:mb-6 prose-p:indent-0"
            dangerouslySetInnerHTML={{ __html: currentChapter.content }} 
        />

        {/* Chapter Actions */}
        <div className="mt-16 mb-8 flex justify-center">
             <button
                onClick={(e) => {
                    e.stopPropagation();
                    if (isCurrentChapterRead) {
                        const newCompleted = completedChapters.filter(c => c !== currentChapterIndex);
                        setCompletedChapters(newCompleted);
                        onUpdateProgress({ ...book.progress, completedChapters: newCompleted });
                    } else {
                        markChapterAsRead(currentChapterIndex);
                    }
                }}
                className={`flex items-center gap-2 px-6 py-2 rounded-full border transition-all ${
                    isCurrentChapterRead 
                    ? 'bg-green-50 border-green-200 text-green-700' 
                    : 'bg-transparent border-gray-300 hover:border-indigo-500 hover:text-indigo-500 opacity-60 hover:opacity-100'
                }`}
             >
                {isCurrentChapterRead ? (
                    <>
                        <CheckCircle size={18} />
                        <span className="font-sans text-sm font-medium">Read</span>
                    </>
                ) : (
                    <>
                        <Circle size={18} />
                        <span className="font-sans text-sm font-medium">Mark as Read</span>
                    </>
                )}
             </button>
        </div>

        {/* Navigation Footer */}
        <div className="flex justify-between items-center pt-10 border-t border-gray-200/20 font-sans">
            <button 
                onClick={(e) => { e.stopPropagation(); handlePrevChapter(); }}
                disabled={currentChapterIndex === 0}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-colors ${currentChapterIndex === 0 ? 'opacity-20 cursor-not-allowed' : 'hover:bg-gray-500/10'}`}
            >
                <ChevronLeft size={20} />
                Previous
            </button>
            <div className="text-sm opacity-50">
                {currentChapterIndex + 1} / {book.chapters.length}
            </div>
            <button 
                onClick={(e) => { e.stopPropagation(); handleNextChapter(); }}
                disabled={currentChapterIndex === book.chapters.length - 1}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-colors ${currentChapterIndex === book.chapters.length - 1 ? 'opacity-20 cursor-not-allowed' : 'hover:bg-gray-500/10'}`}
            >
                Next
                <ChevronRight size={20} />
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Library } from './components/Library';
import { Reader } from './components/Reader';
import { Importer } from './components/Importer';
import { storageService } from './services/storageService';
import { Book, ViewMode } from './types';

function App() {
  const [view, setView] = useState<ViewMode>(ViewMode.LIBRARY);
  const [activeBook, setActiveBook] = useState<Book | null>(null);
  const [library, setLibrary] = useState<Book[]>([]);

  // Load library on mount
  useEffect(() => {
    const loadedBooks = storageService.getLibrary();
    setLibrary(loadedBooks);
  }, []);

  // Handler for completing a conversion
  const handleImportComplete = (newBook: Book) => {
    storageService.saveBook(newBook);
    setLibrary(storageService.getLibrary());
    setActiveBook(newBook);
    setView(ViewMode.READER);
  };

  const handleSelectBook = (book: Book) => {
    setActiveBook(book);
    setView(ViewMode.READER);
  };

  const handleDeleteBook = (id: string) => {
    storageService.deleteBook(id);
    setLibrary(storageService.getLibrary());
  };

  const handleUpdateProgress = (progress: Book['progress']) => {
    if (activeBook) {
      storageService.updateProgress(activeBook.id, progress);
      // Update local state without full reload to prevent jitters, technically optional if unmounting
      setActiveBook(prev => prev ? ({
          ...prev, 
          progress
      }) : null);
    }
  };

  return (
    <div className="antialiased text-gray-900 bg-gray-50 min-h-screen">
      {view === ViewMode.LIBRARY && (
        <Library 
          books={library} 
          onSelectBook={handleSelectBook} 
          onDeleteBook={handleDeleteBook}
          onNavigateImport={() => setView(ViewMode.IMPORTER)}
        />
      )}

      {view === ViewMode.IMPORTER && (
        <Importer 
          onConversionComplete={handleImportComplete}
          onCancel={() => setView(ViewMode.LIBRARY)}
        />
      )}

      {view === ViewMode.READER && activeBook && (
        <Reader 
          book={activeBook} 
          onBack={() => {
              // Refresh library in case progress changed
              setLibrary(storageService.getLibrary());
              setView(ViewMode.LIBRARY);
              setActiveBook(null);
          }}
          onUpdateProgress={handleUpdateProgress}
        />
      )}
    </div>
  );
}

export default App;

export interface Chapter {
  title: string;
  content: string; // HTML or Markdown content
}

export interface Bookmark {
  id: string;
  chapterIndex: number;
  scrollPosition: number;
  label: string;
  createdAt: number;
}

export interface Book {
  id: string;
  title: string;
  author: string;
  coverImage?: string; // Base64 or URL
  chapters: Chapter[];
  createdAt: number;
  bookmarks: Bookmark[]; // New field for bookmarks
  progress: {
    chapterIndex: number;
    scrollPosition: number;
    completedChapters: number[]; // Indices of chapters marked as read
  };
}

export interface ConversionStatus {
  state: 'idle' | 'uploading' | 'processing' | 'success' | 'error';
  message?: string;
}

export enum ViewMode {
  LIBRARY = 'LIBRARY',
  READER = 'READER',
  IMPORTER = 'IMPORTER',
}

import { Book, Bookmark } from '../types';

const STORAGE_KEY = 'lumina_library_v1';

// Simulating a Redis-like key-value store interface
export const storageService = {
  getLibrary: (): Book[] => {
    try {
      const data = localStorage.getItem(STORAGE_KEY);
      if (!data) return [];
      const books = JSON.parse(data);
      // Migration: Ensure completedChapters and bookmarks exist for older records
      return books.map((b: any) => ({
        ...b,
        bookmarks: b.bookmarks || [], // Migration for bookmarks
        progress: {
          chapterIndex: 0,
          scrollPosition: 0,
          ...b.progress, // overwrite defaults
          completedChapters: b.progress?.completedChapters || []
        }
      }));
    } catch (e) {
      console.error("Failed to load library", e);
      return [];
    }
  },

  saveBook: (book: Book): void => {
    const library = storageService.getLibrary();
    // Check if book exists, update if so
    const existingIndex = library.findIndex(b => b.id === book.id);
    if (existingIndex >= 0) {
      library[existingIndex] = book;
    } else {
      library.unshift(book);
    }
    localStorage.setItem(STORAGE_KEY, JSON.stringify(library));
  },

  deleteBook: (bookId: string): void => {
    const library = storageService.getLibrary();
    const newLibrary = library.filter(b => b.id !== bookId);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(newLibrary));
  },

  getBook: (bookId: string): Book | undefined => {
    const library = storageService.getLibrary();
    return library.find(b => b.id === bookId);
  },

  updateProgress: (bookId: string, progress: Book['progress']) => {
    const library = storageService.getLibrary();
    const bookIndex = library.findIndex(b => b.id === bookId);
    if (bookIndex >= 0) {
      library[bookIndex].progress = progress;
      localStorage.setItem(STORAGE_KEY, JSON.stringify(library));
    }
  },

  updateBookmarks: (bookId: string, bookmarks: Bookmark[]) => {
    const library = storageService.getLibrary();
    const bookIndex = library.findIndex(b => b.id === bookId);
    if (bookIndex >= 0) {
      library[bookIndex].bookmarks = bookmarks;
      localStorage.setItem(STORAGE_KEY, JSON.stringify(library));
    }
  }
};

import React, { useState, useCallback } from 'react';
import { Upload, FileText, Loader2, AlertCircle, CheckCircle } from 'lucide-react';
import { convertPdfToBook } from '../services/geminiService';
import { Book } from '../types';

interface ImporterProps {
  onConversionComplete: (book: Book) => void;
  onCancel: () => void;
}

export const Importer: React.FC<ImporterProps> = ({ onConversionComplete, onCancel }) => {
  const [file, setFile] = useState<File | null>(null);
  const [status, setStatus] = useState<'idle' | 'processing' | 'error' | 'success'>('idle');
  const [errorMessage, setErrorMessage] = useState('');

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      if (selectedFile.type === 'application/pdf') {
         setFile(selectedFile);
         setErrorMessage('');
      } else {
         setErrorMessage('Please select a valid PDF file.');
      }
    }
  };

  const handleConvert = async () => {
    if (!file) return;

    setStatus('processing');
    try {
      const apiKey = process.env.API_KEY || ''; // In real app, prompt or env
      if (!apiKey) {
          throw new Error("API Key configuration missing. Please ensure environment variables are set.");
      }

      const bookData = await convertPdfToBook(file, apiKey);

      const newBook: Book = {
        id: crypto.randomUUID(),
        title: bookData.title || file.name.replace('.pdf', ''),
        author: bookData.author || 'Unknown',
        chapters: bookData.chapters || [],
        createdAt: Date.now(),
        bookmarks: [],
        progress: { 
          chapterIndex: 0, 
          scrollPosition: 0, 
          completedChapters: [] 
        },
        coverImage: undefined
      };

      setStatus('success');
      setTimeout(() => {
        onConversionComplete(newBook);
      }, 1500);

    } catch (err: any) {
      console.error(err);
      setStatus('error');
      setErrorMessage(err.message || "Failed to convert book. Please try again.");
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-6">
      <div className="bg-white w-full max-w-2xl rounded-3xl shadow-xl p-8 md:p-12 relative overflow-hidden">
        {/* Background blobs */}
        <div className="absolute top-[-50px] right-[-50px] w-32 h-32 bg-indigo-100 rounded-full blur-3xl opacity-50" />
        <div className="absolute bottom-[-50px] left-[-50px] w-32 h-32 bg-purple-100 rounded-full blur-3xl opacity-50" />

        <div className="relative z-10 text-center">
            <h2 className="text-3xl font-serif font-bold text-gray-900 mb-2">Import Book</h2>
            <p className="text-gray-500 mb-8">Convert your PDF into a reflowable e-book format.</p>

            {status === 'idle' && (
                <div className="border-2 border-dashed border-gray-200 rounded-2xl p-10 bg-gray-50 transition-colors hover:bg-gray-100 hover:border-indigo-300 group">
                    <input 
                        type="file" 
                        accept="application/pdf" 
                        onChange={handleFileChange}
                        className="hidden" 
                        id="file-upload"
                    />

                    {!file ? (
                        <label htmlFor="file-upload" className="cursor-pointer flex flex-col items-center">
                            <div className="bg-white p-4 rounded-full shadow-sm mb-4 group-hover:scale-110 transition-transform">
                                <Upload className="text-indigo-600" size={32} />
                            </div>
                            <span className="font-medium text-gray-900">Click to upload PDF</span>
                            <span className="text-sm text-gray-400 mt-1">Maximum size 10MB</span>
                        </label>
                    ) : (
                        <div className="flex flex-col items-center">
                             <div className="bg-indigo-50 p-4 rounded-full mb-4">
                                <FileText className="text-indigo-600" size={32} />
                            </div>
                            <span className="font-medium text-gray-900 mb-1">{file.name}</span>
                            <span className="text-sm text-gray-400">{(file.size / 1024 / 1024).toFixed(2)} MB</span>
                            <button 
                                onClick={() => setFile(null)}
                                className="text-red-500 text-sm font-medium mt-4 hover:underline"
                            >
                                Remove
                            </button>
                        </div>
                    )}
                </div>
            )}

            {status === 'processing' && (
                <div className="py-12 flex flex-col items-center">
                    <Loader2 className="animate-spin text-indigo-600 mb-4" size={48} />
                    <h3 className="text-lg font-medium text-gray-900">Converting with AI...</h3>
                    <p className="text-sm text-gray-500 mt-2 max-w-xs mx-auto">
                        Gemini is extracting text and structuring chapters. This may take a moment.
                    </p>
                </div>
            )}

            {status === 'success' && (
                <div className="py-12 flex flex-col items-center">
                    <div className="bg-green-100 p-4 rounded-full mb-4">
                        <CheckCircle className="text-green-600" size={48} />
                    </div>
                    <h3 className="text-lg font-medium text-gray-900">Conversion Complete!</h3>
                    <p className="text-sm text-gray-500 mt-2">Adding to your library...</p>
                </div>
            )}

            {status === 'error' && (
                 <div className="py-8 flex flex-col items-center">
                    <div className="bg-red-100 p-4 rounded-full mb-4">
                        <AlertCircle className="text-red-600" size={32} />
                    </div>
                    <h3 className="text-lg font-medium text-gray-900">Conversion Failed</h3>
                    <p className="text-sm text-red-500 mt-2 max-w-sm mx-auto mb-6">{errorMessage}</p>
                    <button 
                        onClick={() => setStatus('idle')}
                        className="px-6 py-2 bg-gray-900 text-white rounded-lg hover:bg-gray-800 transition-colors"
                    >
                        Try Again
                    </button>
                </div>
            )}

            <div className="mt-8 flex gap-4 justify-center">
                {status === 'idle' && (
                    <>
                        <button 
                            onClick={onCancel}
                            className="px-6 py-3 rounded-xl font-medium text-gray-500 hover:bg-gray-100 transition-colors"
                        >
                            Cancel
                        </button>
                        <button 
                            onClick={handleConvert}
                            disabled={!file}
                            className={`px-8 py-3 rounded-xl font-medium text-white transition-all shadow-lg shadow-indigo-200 ${
                                file ? 'bg-indigo-600 hover:bg-indigo-700 hover:scale-105' : 'bg-gray-300 cursor-not-allowed'
                            }`}
                        >
                            Convert to Book
                        </button>
                    </>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Book, Bookmark } from '../types';
import { ArrowLeft, Settings, ChevronLeft, ChevronRight, Menu, CheckCircle, Circle, Bookmark as BookmarkIcon, List, Trash2 } from 'lucide-react';

interface ReaderProps {
  book: Book;
  onBack: () => void;
  onUpdateProgress: (progress: Book['progress']) => void;
  onUpdateBookmarks: (bookmarks: Bookmark[]) => void;
}

export const Reader: React.FC<ReaderProps> = ({ book, onBack, onUpdateProgress, onUpdateBookmarks }) => {
  const [currentChapterIndex, setCurrentChapterIndex] = useState(book.progress.chapterIndex);
  const [completedChapters, setCompletedChapters] = useState<number[]>(book.progress.completedChapters || []);
  const [bookmarks, setBookmarks] = useState<Bookmark[]>(book.bookmarks || []);

  const [fontSize, setFontSize] = useState(18);
  const [theme, setTheme] = useState<'light' | 'sepia' | 'dark'>('sepia');
  const [showControls, setShowControls] = useState(true);
  const [showSidebar, setShowSidebar] = useState(false);
  const [sidebarTab, setSidebarTab] = useState<'toc' | 'bookmarks'>('toc');

  // Used to handle programmatic scrolling after state updates
  const [targetScroll, setTargetScroll] = useState<number | null>(null);

  const contentRef = useRef<HTMLDivElement>(null);

  const currentChapter = book.chapters[currentChapterIndex];
  const isCurrentChapterRead = completedChapters.includes(currentChapterIndex);

  // Initial scroll restoration and scroll syncing after navigation/bookmarks
  useEffect(() => {
     if (targetScroll !== null) {
         setTimeout(() => {
             window.scrollTo(0, targetScroll);
         }, 100);
         setTargetScroll(null);
     } else if (currentChapterIndex === book.progress.chapterIndex) {
         // If we are just opening the book or normal nav, restore saved progress
         setTimeout(() => {
             window.scrollTo(0, book.progress.scrollPosition);
         }, 100);
     } else {
         window.scrollTo(0, 0);
     }
  }, [currentChapterIndex, targetScroll]);

  // Sync scroll position to parent for persistence
  useEffect(() => {
      const handleScroll = () => {
          onUpdateProgress({
            chapterIndex: currentChapterIndex,
            scrollPosition: window.scrollY,
            completedChapters
          });
      };

      window.addEventListener('scroll', handleScroll);
      return () => window.removeEventListener('scroll', handleScroll);
  }, [currentChapterIndex, completedChapters, onUpdateProgress]);

  const markChapterAsRead = (index: number) => {
    if (!completedChapters.includes(index)) {
      const newCompleted = [...completedChapters, index];
      setCompletedChapters(newCompleted);
      onUpdateProgress({
        chapterIndex: currentChapterIndex,
        scrollPosition: window.scrollY,
        completedChapters: newCompleted
      });
    }
  };

  const handleNextChapter = () => {
    markChapterAsRead(currentChapterIndex);
    if (currentChapterIndex < book.chapters.length - 1) {
      setCurrentChapterIndex(prev => prev + 1);
      window.scrollTo(0, 0);
    }
  };

  const handlePrevChapter = () => {
    if (currentChapterIndex > 0) {
      setCurrentChapterIndex(prev => prev - 1);
      window.scrollTo(0, 0);
    }
  };

  const handleAddBookmark = () => {
      const newBookmark: Bookmark = {
          id: crypto.randomUUID(),
          chapterIndex: currentChapterIndex,
          scrollPosition: window.scrollY,
          label: `${currentChapter.title} - ${new Date().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}`,
          createdAt: Date.now()
      };

      const updatedBookmarks = [newBookmark, ...bookmarks];
      setBookmarks(updatedBookmarks);
      onUpdateBookmarks(updatedBookmarks);

      // Brief feedback could go here
      alert("Bookmark added!");
  };

  const handleRemoveBookmark = (id: string) => {
      const updatedBookmarks = bookmarks.filter(b => b.id !== id);
      setBookmarks(updatedBookmarks);
      onUpdateBookmarks(updatedBookmarks);
  };

  const handleJumpToBookmark = (bm: Bookmark) => {
      setTargetScroll(bm.scrollPosition);
      if (bm.chapterIndex !== currentChapterIndex) {
          setCurrentChapterIndex(bm.chapterIndex);
      } else {
          // Same chapter, force scroll effect manually if needed or let effect run (deps on targetScroll)
          setTimeout(() => window.scrollTo(0, bm.scrollPosition), 100);
      }
      setShowSidebar(false);
  };

  const toggleControls = () => {
    setShowControls(prev => !prev);
  };

  const getThemeColors = () => {
    switch(theme) {
      case 'dark': return 'bg-gray-900 text-gray-300';
      case 'sepia': return 'bg-paper-dark text-ink';
      default: return 'bg-white text-gray-900';
    }
  };

  // Calculate overall progress
  const progressPercent = Math.round((completedChapters.length / book.chapters.length) * 100);

  return (
    <div className={`min-h-screen transition-colors duration-500 ${getThemeColors()} font-serif`}>
      {/* Sticky Header */}
      <div 
        className={`fixed top-0 left-0 right-0 p-4 flex flex-col justify-center transition-transform duration-300 z-50 ${
          showControls ? 'translate-y-0' : '-translate-y-full'
        } ${theme === 'dark' ? 'bg-gray-900/95' : 'bg-white/95'} backdrop-blur-sm border-b ${theme === 'dark' ? 'border-gray-800' : 'border-gray-100'}`}
      >
        <div className="flex justify-between items-center w-full max-w-5xl mx-auto">
            <div className="flex items-center gap-4">
                <button onClick={onBack} className="p-2 rounded-full hover:bg-gray-100/10 transition-colors">
                    <ArrowLeft size={20} className={theme === 'dark' ? 'text-gray-300' : 'text-gray-700'} />
                </button>
                <button onClick={() => setShowSidebar(!showSidebar)} className="p-2 rounded-full hover:bg-gray-100/10 transition-colors">
                    <Menu size={20} className={theme === 'dark' ? 'text-gray-300' : 'text-gray-700'} />
                </button>
                <div className="hidden md:block">
                     <h2 className="font-sans font-medium text-sm truncate max-w-[200px]">{book.title}</h2>
                     <div className="w-32 h-1 bg-gray-200 rounded-full mt-1 overflow-hidden">
                        <div className="h-full bg-indigo-500 transition-all duration-300" style={{ width: `${progressPercent}%` }}></div>
                     </div>
                </div>
            </div>

            <div className="flex items-center gap-4">
                <button 
                    onClick={handleAddBookmark}
                    className="p-2 rounded-full hover:bg-gray-100/10 transition-colors text-indigo-500"
                    title="Add Bookmark"
                >
                    <BookmarkIcon size={22} fill={theme === 'dark' ? 'none' : 'currentColor'} className="text-indigo-500" />
                </button>

                <div className="flex items-center gap-2 bg-gray-100/10 rounded-full p-1 border border-gray-200/20">
                    <button 
                        onClick={() => setFontSize(Math.max(14, fontSize - 2))}
                        className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-500/10 font-sans text-sm"
                    >
                        A-
                    </button>
                    <span className="text-xs font-sans w-4 text-center">{fontSize}</span>
                    <button 
                        onClick={() => setFontSize(Math.min(32, fontSize + 2))}
                        className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-500/10 font-sans text-lg"
                    >
                        A+
                    </button>
                </div>

                <div className="flex items-center gap-1">
                    <button onClick={() => setTheme('light')} className={`w-6 h-6 rounded-full border border-gray-300 bg-white ${theme === 'light' ? 'ring-2 ring-indigo-500' : ''}`} />
                    <button onClick={() => setTheme('sepia')} className={`w-6 h-6 rounded-full border border-orange-200 bg-[#eaddcf] ${theme === 'sepia' ? 'ring-2 ring-indigo-500' : ''}`} />
                    <button onClick={() => setTheme('dark')} className={`w-6 h-6 rounded-full border border-gray-700 bg-gray-900 ${theme === 'dark' ? 'ring-2 ring-indigo-500' : ''}`} />
                </div>
            </div>
        </div>
      </div>

      {/* Sidebar (TOC & Bookmarks) */}
      {showSidebar && (
        <div className="fixed inset-0 z-40 bg-black/50" onClick={() => setShowSidebar(false)}>
            <div 
                className={`absolute left-0 top-0 bottom-0 w-80 max-w-[85%] ${theme === 'dark' ? 'bg-gray-900' : 'bg-white'} shadow-2xl overflow-hidden flex flex-col`}
                onClick={e => e.stopPropagation()}
            >
                {/* Sidebar Header/Tabs */}
                <div className="flex border-b border-gray-200/20">
                    <button 
                        onClick={() => setSidebarTab('toc')}
                        className={`flex-1 py-4 text-sm font-sans font-medium transition-colors ${sidebarTab === 'toc' ? 'text-indigo-500 border-b-2 border-indigo-500' : 'text-gray-500'}`}
                    >
                        Chapters
                    </button>
                    <button 
                        onClick={() => setSidebarTab('bookmarks')}
                        className={`flex-1 py-4 text-sm font-sans font-medium transition-colors ${sidebarTab === 'bookmarks' ? 'text-indigo-500 border-b-2 border-indigo-500' : 'text-gray-500'}`}
                    >
                        Bookmarks
                    </button>
                </div>

                {/* Sidebar Content */}
                <div className="flex-1 overflow-y-auto p-6">
                    {sidebarTab === 'toc' ? (
                        <ul className="space-y-4">
                            {book.chapters.map((chap, idx) => {
                                const isRead = completedChapters.includes(idx);
                                return (
                                    <li key={idx} className="flex items-start gap-3">
                                        <button
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                if (isRead) {
                                                    const newCompleted = completedChapters.filter(c => c !== idx);
                                                    setCompletedChapters(newCompleted);
                                                    onUpdateProgress({ ...book.progress, completedChapters: newCompleted });
                                                } else {
                                                    markChapterAsRead(idx);
                                                }
                                            }}
                                            className={`mt-1 flex-shrink-0 hover:opacity-80 transition-opacity ${isRead ? 'text-green-500' : 'text-gray-300'}`}
                                        >
                                            {isRead ? <CheckCircle size={16} /> : <Circle size={16} />}
                                        </button>
                                        <button 
                                            onClick={() => {
                                                setCurrentChapterIndex(idx);
                                                setShowSidebar(false);
                                                window.scrollTo(0,0);
                                            }}
                                            className={`text-left w-full hover:text-indigo-500 transition-colors ${currentChapterIndex === idx ? 'text-indigo-500 font-bold' : ''}`}
                                        >
                                            {chap.title}
                                        </button>
                                    </li>
                                );
                            })}
                        </ul>
                    ) : (
                        <div className="space-y-4">
                            {bookmarks.length === 0 ? (
                                <div className="text-center text-gray-500 py-10">
                                    <BookmarkIcon className="mx-auto mb-3 opacity-30" size={32} />
                                    <p>No bookmarks yet.</p>
                                    <p className="text-xs mt-1">Tap the bookmark icon in the top right to save your spot.</p>
                                </div>
                            ) : (
                                <ul className="space-y-4">
                                    {bookmarks.map((bm) => (
                                        <li key={bm.id} className="group flex items-start justify-between gap-2 p-3 rounded-lg hover:bg-gray-100/10 border border-transparent hover:border-gray-200/20">
                                            <button 
                                                onClick={() => handleJumpToBookmark(bm)}
                                                className="text-left flex-1"
                                            >
                                                <div className="text-sm font-bold font-serif mb-1">{bm.label}</div>
                                                <div className="text-xs text-gray-400">
                                                    {new Date(bm.createdAt).toLocaleDateString()}
                                                </div>
                                            </button>
                                            <button 
                                                onClick={(e) => { e.stopPropagation(); handleRemoveBookmark(bm.id); }}
                                                className="opacity-0 group-hover:opacity-100 text-gray-400 hover:text-red-500 transition-all"
                                            >
                                                <Trash2 size={16} />
                                            </button>
                                        </li>
                                    ))}
                                </ul>
                            )}
                        </div>
                    )}
                </div>
            </div>
        </div>
      )}

      {/* Main Content */}
      <div 
        className="max-w-2xl mx-auto px-6 py-24 md:px-12 min-h-screen cursor-text"
        onClick={toggleControls}
      >
        <div className="mb-12 text-center">
             <h3 className="font-sans text-xs uppercase tracking-widest opacity-50 mb-2">Chapter {currentChapterIndex + 1}</h3>
             <h1 className="text-3xl md:text-4xl font-bold">{currentChapter.title}</h1>
        </div>

        <div 
            ref={contentRef}
            style={{ fontSize: `${fontSize}px`, lineHeight: '1.8' }}
            className="prose prose-lg max-w-none prose-p:mb-6 prose-p:indent-0"
            dangerouslySetInnerHTML={{ __html: currentChapter.content }} 
        />

        {/* Chapter Actions */}
        <div className="mt-16 mb-8 flex justify-center">
             <button
                onClick={(e) => {
                    e.stopPropagation();
                    if (isCurrentChapterRead) {
                        const newCompleted = completedChapters.filter(c => c !== currentChapterIndex);
                        setCompletedChapters(newCompleted);
                        onUpdateProgress({ ...book.progress, completedChapters: newCompleted });
                    } else {
                        markChapterAsRead(currentChapterIndex);
                    }
                }}
                className={`flex items-center gap-2 px-6 py-2 rounded-full border transition-all ${
                    isCurrentChapterRead 
                    ? 'bg-green-50 border-green-200 text-green-700' 
                    : 'bg-transparent border-gray-300 hover:border-indigo-500 hover:text-indigo-500 opacity-60 hover:opacity-100'
                }`}
             >
                {isCurrentChapterRead ? (
                    <>
                        <CheckCircle size={18} />
                        <span className="font-sans text-sm font-medium">Read</span>
                    </>
                ) : (
                    <>
                        <Circle size={18} />
                        <span className="font-sans text-sm font-medium">Mark as Read</span>
                    </>
                )}
             </button>
        </div>

        {/* Navigation Footer */}
        <div className="flex justify-between items-center pt-10 border-t border-gray-200/20 font-sans">
            <button 
                onClick={(e) => { e.stopPropagation(); handlePrevChapter(); }}
                disabled={currentChapterIndex === 0}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-colors ${currentChapterIndex === 0 ? 'opacity-20 cursor-not-allowed' : 'hover:bg-gray-500/10'}`}
            >
                <ChevronLeft size={20} />
                Previous
            </button>
            <div className="text-sm opacity-50">
                {currentChapterIndex + 1} / {book.chapters.length}
            </div>
            <button 
                onClick={(e) => { e.stopPropagation(); handleNextChapter(); }}
                disabled={currentChapterIndex === book.chapters.length - 1}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-colors ${currentChapterIndex === book.chapters.length - 1 ? 'opacity-20 cursor-not-allowed' : 'hover:bg-gray-500/10'}`}
            >
                Next
                <ChevronRight size={20} />
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Library } from './components/Library';
import { Reader } from './components/Reader';
import { Importer } from './components/Importer';
import { storageService } from './services/storageService';
import { Book, Bookmark, ViewMode } from './types';

function App() {
  const [view, setView] = useState<ViewMode>(ViewMode.LIBRARY);
  const [activeBook, setActiveBook] = useState<Book | null>(null);
  const [library, setLibrary] = useState<Book[]>([]);

  // Load library on mount
  useEffect(() => {
    const loadedBooks = storageService.getLibrary();
    setLibrary(loadedBooks);
  }, []);

  // Handler for completing a conversion
  const handleImportComplete = (newBook: Book) => {
    storageService.saveBook(newBook);
    setLibrary(storageService.getLibrary());
    setActiveBook(newBook);
    setView(ViewMode.READER);
  };

  const handleSelectBook = (book: Book) => {
    setActiveBook(book);
    setView(ViewMode.READER);
  };

  const handleDeleteBook = (id: string) => {
    storageService.deleteBook(id);
    setLibrary(storageService.getLibrary());
  };

  const handleUpdateProgress = (progress: Book['progress']) => {
    if (activeBook) {
      storageService.updateProgress(activeBook.id, progress);
      // Update local state without full reload
      setActiveBook(prev => prev ? ({
          ...prev, 
          progress
      }) : null);
    }
  };

  const handleUpdateBookmarks = (bookmarks: Bookmark[]) => {
    if (activeBook) {
        storageService.updateBookmarks(activeBook.id, bookmarks);
        // Update local state
        setActiveBook(prev => prev ? ({
            ...prev,
            bookmarks
        }) : null);
    }
  };

  return (
    <div className="antialiased text-gray-900 bg-gray-50 min-h-screen">
      {view === ViewMode.LIBRARY && (
        <Library 
          books={library} 
          onSelectBook={handleSelectBook} 
          onDeleteBook={handleDeleteBook}
          onNavigateImport={() => setView(ViewMode.IMPORTER)}
        />
      )}

      {view === ViewMode.IMPORTER && (
        <Importer 
          onConversionComplete={handleImportComplete}
          onCancel={() => setView(ViewMode.LIBRARY)}
        />
      )}

      {view === ViewMode.READER && activeBook && (
        <Reader 
          book={activeBook} 
          onBack={() => {
              // Refresh library in case progress changed
              setLibrary(storageService.getLibrary());
              setView(ViewMode.LIBRARY);
              setActiveBook(null);
          }}
          onUpdateProgress={handleUpdateProgress}
          onUpdateBookmarks={handleUpdateBookmarks}
        />
      )}
    </div>
  );
}

export default App;

