import { Book, Chapter } from '../types';

declare global {
  interface Window {
    pdfjsLib: any;
  }
}

export const processFileToBook = async (file: File): Promise<Partial<Book>> => {
  const fileName = file.name;
  const fileType = file.type;

  // Handle Text and Markdown files
  if (fileType === 'text/plain' || fileName.endsWith('.md') || fileName.endsWith('.txt')) {
    const text = await file.text();
    const formattedContent = text
      .split('\n\n')
      .map(para => `<p>${para.trim()}</p>`)
      .join('');

    return {
      title: fileName.replace(/\.(txt|md)$/i, ''),
      author: 'Local Document',
      chapters: [
        {
          title: 'Document Content',
          content: formattedContent || '<p><em>Empty file</em></p>'
        }
      ]
    };
  }

  // Real Client-Side PDF Extraction
  if (fileType === 'application/pdf') {
    return await extractPdfContent(file);
  }

  throw new Error("Unsupported file type");
};

const extractPdfContent = async (file: File): Promise<Partial<Book>> => {
  if (!window.pdfjsLib) {
    throw new Error("PDF parser library not loaded. Please check your internet connection.");
  }

  const arrayBuffer = await file.arrayBuffer();
  const loadingTask = window.pdfjsLib.getDocument({ data: arrayBuffer });
  const pdf = await loadingTask.promise;

  let fullText = "";
  const chapters: Chapter[] = [];
  let currentChapterContent = "";
  let currentChapterTitle = "Start of Book";

  // Configuration for heuristics
  const PAGES_PER_CHAPTER = 20; // Fallback: split every 20 pages if no headers found

  for (let pageNum = 1; pageNum <= pdf.numPages; pageNum++) {
    const page = await pdf.getPage(pageNum);
    const textContent = await page.getTextContent();

    // Simple heuristic to reconstruct paragraphs from lines
    let pageText = "";
    let lastY = -1;

    // Sort items by vertical position (top to bottom) then horizontal
    const items = textContent.items.sort((a: any, b: any) => {
        if (Math.abs(a.transform[5] - b.transform[5]) > 5) {
            return b.transform[5] - a.transform[5]; // Top to bottom
        }
        return a.transform[4] - b.transform[4]; // Left to right
    });

    for (const item of items) {
       const text = item.str;
       if (!text.trim()) continue;

       // Check for vertical gap implying new paragraph
       if (lastY !== -1 && Math.abs(item.transform[5] - lastY) > 12) {
           pageText += "\n"; 
       } else if (pageText.length > 0 && !pageText.endsWith(" ") && !pageText.endsWith("\n")) {
           pageText += " ";
       }

       pageText += text;
       lastY = item.transform[5];
    }

    // Wrap page text in paragraphs
    const paragraphs = pageText.split('\n').filter(p => p.trim().length > 0);
    const htmlContent = paragraphs.map(p => `<p>${p}</p>`).join('');

    currentChapterContent += htmlContent;

    // Split logic: Arbitrary chunking to prevent massive DOM nodes
    // In a real reader, we might look for "Chapter" regex in the text
    if (pageNum % PAGES_PER_CHAPTER === 0 || pageNum === pdf.numPages) {
        chapters.push({
            title: currentChapterTitle + (chapters.length > 0 ? ` (Part ${chapters.length + 1})` : ''),
            content: currentChapterContent
        });
        currentChapterContent = "";
        currentChapterTitle = `Part ${chapters.length + 1}`;
    }
  }

  // If the PDF is small (fewer than PAGES_PER_CHAPTER), push what we have
  if (chapters.length === 0 && currentChapterContent.length > 0) {
      chapters.push({
          title: "Full Text",
          content: currentChapterContent
      });
  }

  return {
    title: file.name.replace('.pdf', ''),
    author: 'Imported PDF',
    chapters: chapters
  };
};

import { Book } from '../types';

declare global {
  interface Window {
    JSZip: any;
  }
}

export const generateEpub = async (book: Book): Promise<Blob> => {
  if (!window.JSZip) {
    throw new Error('JSZip library not loaded');
  }

  const zip = new window.JSZip();

  // 1. Mimetype file (must be first, uncompressed)
  zip.file('mimetype', 'application/epub+zip', { compression: 'STORE' });

  // 2. META-INF/container.xml
  zip.folder('META-INF').file('container.xml', `<?xml version="1.0"?>
<container version="1.0" xmlns="urn:oasis:names:tc:opendocument:xmlns:container">
   <rootfiles>
      <rootfile full-path="OEBPS/content.opf" media-type="application/oebps-package+xml"/>
   </rootfiles>
</container>`);

  // 3. OEBPS folder structure
  const oebps = zip.folder('OEBPS');

  // Generate unique IDs
  const uniqueId = `urn:uuid:${book.id}`;
  const timestamp = new Date().toISOString();

  // Create HTML files for each chapter
  let manifestItems = '';
  let spineRefs = '';
  let navPoints = '';

  book.chapters.forEach((chapter, index) => {
    const fileName = `chapter_${index + 1}.xhtml`;
    const fileId = `chap${index + 1}`;

    // Minimal valid XHTML for EPUB
    const xhtml = `<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE html PUBLIC "-//W3C//DTD XHTML 1.1//EN" "http://www.w3.org/TR/xhtml11/DTD/xhtml11.dtd">
<html xmlns="http://www.w3.org/1999/xhtml" xml:lang="en">
<head>
<title>${chapter.title}</title>
<style>
body { font-family: serif; line-height: 1.5; margin: 5%; }
p { margin-bottom: 1em; text-indent: 1em; }
</style>
</head>
<body>
<h2>${chapter.title}</h2>
${chapter.content}
</body>
</html>`;

    oebps.file(fileName, xhtml);

    // Add to manifest
    manifestItems += `<item id="${fileId}" href="${fileName}" media-type="application/xhtml+xml" />\n`;
    // Add to spine
    spineRefs += `<itemref idref="${fileId}" />\n`;
    // Add to NCX
    navPoints += `
    <navPoint id="navPoint-${index + 1}" playOrder="${index + 1}">
      <navLabel><text>${chapter.title}</text></navLabel>
      <content src="${fileName}"/>
    </navPoint>`;
  });

  // 4. Content.opf
  const opfContent = `<?xml version="1.0" encoding="UTF-8"?>
<package xmlns="http://www.idpf.org/2007/opf" unique-identifier="BookId" version="2.0">
   <metadata xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:opf="http://www.idpf.org/2007/opf">
      <dc:title>${book.title}</dc:title>
      <dc:creator opf:role="aut">${book.author}</dc:creator>
      <dc:language>en</dc:language>
      <dc:identifier id="BookId" opf:scheme="UUID">${uniqueId}</dc:identifier>
      <dc:date>${timestamp}</dc:date>
   </metadata>
   <manifest>
      <item id="ncx" href="toc.ncx" media-type="application/x-dtbncx+xml"/>
      ${manifestItems}
   </manifest>
   <spine toc="ncx">
      ${spineRefs}
   </spine>
</package>`;

  oebps.file('content.opf', opfContent);

  // 5. TOC.ncx (for navigation)
  const ncxContent = `<?xml version="1.0" encoding="UTF-8"?>
<ncx xmlns="http://www.daisy.org/z3986/2005/ncx/" version="2005-1">
   <head>
      <meta name="dtb:uid" content="${uniqueId}"/>
      <meta name="dtb:depth" content="1"/>
      <meta name="dtb:totalPageCount" content="0"/>
      <meta name="dtb:maxPageNumber" content="0"/>
   </head>
   <docTitle><text>${book.title}</text></docTitle>
   <navMap>
      ${navPoints}
   </navMap>
</ncx>`;

  oebps.file('toc.ncx', ncxContent);

  // Generate blob
  return await zip.generateAsync({ type: 'blob' });
};

import React from 'react';
import { Book } from '../types';
import { BookOpen, Trash2, Plus, Clock, CheckCircle2, Download } from 'lucide-react';
import { generateEpub } from '../services/epubGenerator';

interface LibraryProps {
  books: Book[];
  onSelectBook: (book: Book) => void;
  onDeleteBook: (id: string) => void;
  onNavigateImport: () => void;
}

export const Library: React.FC<LibraryProps> = ({ books, onSelectBook, onDeleteBook, onNavigateImport }) => {

  const handleDownloadEpub = async (e: React.MouseEvent, book: Book) => {
    e.stopPropagation();
    try {
      const blob = await generateEpub(book);
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${book.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.epub`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    } catch (err) {
      console.error("Failed to generate EPUB", err);
      alert("Failed to generate EPUB file.");
    }
  };

  return (
    <div className="p-8 max-w-7xl mx-auto min-h-screen">
      <div className="flex justify-between items-center mb-12">
        <div>
          <h1 className="text-4xl font-serif font-bold text-gray-900 mb-2">My Library</h1>
          <p className="text-gray-500">Your collection of converted books</p>
        </div>
        <button
          onClick={onNavigateImport}
          className="flex items-center gap-2 bg-gray-900 text-white px-6 py-3 rounded-full hover:bg-gray-800 transition-all shadow-lg hover:shadow-xl"
        >
          <Plus size={20} />
          <span>Add Book</span>
        </button>
      </div>

      {books.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-20 bg-white rounded-3xl border border-gray-100 shadow-sm text-center">
          <div className="bg-gray-50 p-6 rounded-full mb-6">
            <BookOpen size={48} className="text-gray-300" />
          </div>
          <h3 className="text-xl font-medium text-gray-900 mb-2">Your library is empty</h3>
          <p className="text-gray-500 max-w-md mb-8">
            Upload a PDF, Text, or Markdown file to add it to your personal library.
          </p>
          <button
            onClick={onNavigateImport}
            className="text-indigo-600 font-medium hover:text-indigo-800 transition-colors"
          >
            Start reading now &rarr;
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
          {books.map((book) => {
            const completedCount = book.progress.completedChapters?.length || 0;
            const totalCount = book.chapters.length;
            const percent = totalCount > 0 ? Math.round((completedCount / totalCount) * 100) : 0;

            return (
              <div 
                key={book.id} 
                className="group relative bg-white rounded-xl shadow-sm hover:shadow-md transition-all duration-300 overflow-hidden border border-gray-100 flex flex-col h-[340px]"
              >
                {/* Cover Mockup */}
                <div 
                  className="h-40 bg-gradient-to-br from-indigo-50 to-purple-50 p-6 flex flex-col justify-center items-center text-center cursor-pointer relative"
                  onClick={() => onSelectBook(book)}
                >
                   {book.coverImage ? (
                     <img src={book.coverImage} alt={book.title} className="w-full h-full object-cover opacity-80" />
                   ) : (
                     <>
                        <BookOpen size={32} className="text-indigo-200 mb-2" />
                        <h3 className="font-serif font-bold text-gray-800 line-clamp-2 px-4 text-lg leading-tight">
                          {book.title}
                        </h3>
                     </>
                   )}
                   <div className="absolute inset-0 bg-black bg-opacity-0 group-hover:bg-opacity-5 transition-all" />
                </div>

                {/* Book Info */}
                <div className="p-5 flex-1 flex flex-col justify-between">
                  <div>
                    <p className="text-sm font-medium text-gray-400 uppercase tracking-wider text-xs mb-1">
                      {book.author}
                    </p>
                    <h4 className="font-medium text-gray-900 line-clamp-1 mb-2" title={book.title}>
                      {book.title}
                    </h4>
                    <div className="flex items-center gap-2 text-xs text-gray-500">
                      <Clock size={12} />
                      <span>{book.chapters.length} Chapters</span>
                    </div>
                  </div>

                  {/* Progress Bar & Actions */}
                  <div className="mt-4">
                    <div className="w-full bg-gray-100 rounded-full h-1.5 mb-2">
                      <div 
                        className="bg-indigo-600 h-1.5 rounded-full transition-all duration-500" 
                        style={{ width: `${percent}%` }}
                      ></div>
                    </div>

                    <div className="flex justify-between items-center pt-1">
                       <div className="text-xs text-gray-400">
                          {percent > 0 ? (
                            <span className="text-indigo-600 font-medium flex items-center gap-1">
                              {percent === 100 && <CheckCircle2 size={12} />}
                              {percent}% Read
                            </span>
                          ) : (
                            "New"
                          )}
                       </div>

                       <div className="flex gap-1">
                         <button
                          onClick={(e) => handleDownloadEpub(e, book)}
                          className="text-gray-300 hover:text-indigo-600 transition-colors p-1"
                          title="Download as EPUB"
                         >
                           <Download size={16} />
                         </button>
                         <button
                          onClick={(e) => {
                            e.stopPropagation();
                            if(window.confirm('Delete this book?')) onDeleteBook(book.id);
                          }}
                          className="text-gray-300 hover:text-red-500 transition-colors p-1"
                          title="Delete book"
                         >
                           <Trash2 size={16} />
                         </button>
                       </div>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Upload, FileText, Loader2, AlertCircle, CheckCircle } from 'lucide-react';
import { processFileToBook } from '../services/conversionService';
import { Book } from '../types';

interface ImporterProps {
  onConversionComplete: (book: Book) => void;
  onCancel: () => void;
}

export const Importer: React.FC<ImporterProps> = ({ onConversionComplete, onCancel }) => {
  const [file, setFile] = useState<File | null>(null);
  const [status, setStatus] = useState<'idle' | 'processing' | 'error' | 'success'>('idle');
  const [errorMessage, setErrorMessage] = useState('');

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      const validTypes = ['application/pdf', 'text/plain', 'text/markdown'];
      const fileName = selectedFile.name.toLowerCase();

      if (validTypes.includes(selectedFile.type) || fileName.endsWith('.md') || fileName.endsWith('.txt')) {
         setFile(selectedFile);
         setErrorMessage('');
      } else {
         setErrorMessage('Please select a valid PDF, Text, or Markdown file.');
      }
    }
  };

  const handleConvert = async () => {
    if (!file) return;

    setStatus('processing');
    try {
      const bookData = await processFileToBook(file);

      const newBook: Book = {
        id: crypto.randomUUID(),
        title: bookData.title || file.name,
        author: bookData.author || 'Unknown',
        chapters: bookData.chapters || [],
        createdAt: Date.now(),
        bookmarks: [],
        progress: { 
          chapterIndex: 0, 
          scrollPosition: 0, 
          completedChapters: [] 
        },
        coverImage: undefined
      };

      setStatus('success');
      setTimeout(() => {
        onConversionComplete(newBook);
      }, 1500);

    } catch (err: any) {
      console.error(err);
      setStatus('error');
      setErrorMessage(err.message || "Failed to process file.");
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-6">
      <div className="bg-white w-full max-w-2xl rounded-3xl shadow-xl p-8 md:p-12 relative overflow-hidden">
        {/* Background blobs */}
        <div className="absolute top-[-50px] right-[-50px] w-32 h-32 bg-indigo-100 rounded-full blur-3xl opacity-50" />
        <div className="absolute bottom-[-50px] left-[-50px] w-32 h-32 bg-purple-100 rounded-full blur-3xl opacity-50" />

        <div className="relative z-10 text-center">
            <h2 className="text-3xl font-serif font-bold text-gray-900 mb-2">Import Book</h2>
            <p className="text-gray-500 mb-8">Convert PDF, Text, or Markdown files to reading format.</p>

            {status === 'idle' && (
                <div className="border-2 border-dashed border-gray-200 rounded-2xl p-10 bg-gray-50 transition-colors hover:bg-gray-100 hover:border-indigo-300 group">
                    <input 
                        type="file" 
                        accept=".pdf,.txt,.md" 
                        onChange={handleFileChange}
                        className="hidden" 
                        id="file-upload"
                    />

                    {!file ? (
                        <label htmlFor="file-upload" className="cursor-pointer flex flex-col items-center">
                            <div className="bg-white p-4 rounded-full shadow-sm mb-4 group-hover:scale-110 transition-transform">
                                <Upload className="text-indigo-600" size={32} />
                            </div>
                            <span className="font-medium text-gray-900">Click to upload file</span>
                            <span className="text-sm text-gray-400 mt-1">PDF, TXT, or MD (Max 10MB)</span>
                        </label>
                    ) : (
                        <div className="flex flex-col items-center">
                             <div className="bg-indigo-50 p-4 rounded-full mb-4">
                                <FileText className="text-indigo-600" size={32} />
                            </div>
                            <span className="font-medium text-gray-900 mb-1">{file.name}</span>
                            <span className="text-sm text-gray-400">{(file.size / 1024 / 1024).toFixed(2)} MB</span>
                            <button 
                                onClick={() => setFile(null)}
                                className="text-red-500 text-sm font-medium mt-4 hover:underline"
                            >
                                Remove
                            </button>
                        </div>
                    )}
                </div>
            )}

            {status === 'processing' && (
                <div className="py-12 flex flex-col items-center">
                    <Loader2 className="animate-spin text-indigo-600 mb-4" size={48} />
                    <h3 className="text-lg font-medium text-gray-900">Converting...</h3>
                    <p className="text-sm text-gray-500 mt-2 max-w-xs mx-auto">
                        Extracting text and formatting your book as EPUB structure.
                    </p>
                </div>
            )}

            {status === 'success' && (
                <div className="py-12 flex flex-col items-center">
                    <div className="bg-green-100 p-4 rounded-full mb-4">
                        <CheckCircle className="text-green-600" size={48} />
                    </div>
                    <h3 className="text-lg font-medium text-gray-900">Import Complete!</h3>
                    <p className="text-sm text-gray-500 mt-2">Book added to your library.</p>
                </div>
            )}

            {status === 'error' && (
                 <div className="py-8 flex flex-col items-center">
                    <div className="bg-red-100 p-4 rounded-full mb-4">
                        <AlertCircle className="text-red-600" size={32} />
                    </div>
                    <h3 className="text-lg font-medium text-gray-900">Import Failed</h3>
                    <p className="text-sm text-red-500 mt-2 max-w-sm mx-auto mb-6">{errorMessage}</p>
                    <button 
                        onClick={() => setStatus('idle')}
                        className="px-6 py-2 bg-gray-900 text-white rounded-lg hover:bg-gray-800 transition-colors"
                    >
                        Try Again
                    </button>
                </div>
            )}

            <div className="mt-8 flex gap-4 justify-center">
                {status === 'idle' && (
                    <>
                        <button 
                            onClick={onCancel}
                            className="px-6 py-3 rounded-xl font-medium text-gray-500 hover:bg-gray-100 transition-colors"
                        >
                            Cancel
                        </button>
                        <button 
                            onClick={handleConvert}
                            disabled={!file}
                            className={`px-8 py-3 rounded-xl font-medium text-white transition-all shadow-lg shadow-indigo-200 ${
                                file ? 'bg-indigo-600 hover:bg-indigo-700 hover:scale-105' : 'bg-gray-300 cursor-not-allowed'
                            }`}
                        >
                            Convert & Import
                        </button>
                    </>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};
